<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Falling Sand Simulator</title>
  <style>
    * {
      margin: 0;
      padding: 0;
      box-sizing: border-box;
    }

    body {
      background: #1a1a1a;
      color: #fff;
      font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      min-height: 100vh;
      padding: 20px;
      gap: 20px;
    }

    .container {
      display: flex;
      flex-direction: column;
      align-items: center;
      gap: 20px;
    }

    h1 {
      font-size: 28px;
      font-weight: 600;
    }

    canvas {
      border: 1px solid #444;
      background: #0a0a0a;
      cursor: crosshair;
      display: block;
      image-rendering: pixelated;
    }

    .controls {
      display: flex;
      gap: 10px;
      flex-wrap: wrap;
      justify-content: center;
      align-items: center;
    }

    button {
      padding: 10px 16px;
      border: none;
      border-radius: 4px;
      font-size: 14px;
      font-weight: 500;
      cursor: pointer;
      transition: all 0.2s;
      background: #333;
      color: #fff;
    }

    button:hover {
      background: #444;
    }

    button:active {
      transform: scale(0.98);
    }

    #mat-sand.active {
      background: #FFB74D;
      color: #333;
    }

    #mat-water.active {
      background: #42A5F5;
      color: #fff;
    }

    #mat-wall.active {
      background: #616161;
      color: #fff;
    }

    #mat-acid.active {
      background: #66BB6A;
      color: #fff;
    }

    #mat-empty.active {
      background: #9E9E9E;
      color: #333;
    }

    #clear {
      background: #D32F2F;
    }

    #clear:hover {
      background: #E53935;
    }
  </style>
</head>
<body>
  <div class="container">
    <h1>Falling Sand</h1>
    <canvas id="sand" width="400" height="400"></canvas>
    <div class="controls">
      <button id="mat-sand" class="mat-btn active">Sand</button>
      <button id="mat-water" class="mat-btn">Water</button>
      <button id="mat-wall" class="mat-btn">Wall</button>
      <button id="mat-acid" class="mat-btn">Acid</button>
      <button id="mat-empty" class="mat-btn">Eraser</button>
      <button id="clear">Clear</button>
    </div>
  </div>

  <script>
    const CELL_TYPES = {
      EMPTY: 'empty',
      SAND: 'sand',
      WATER: 'water',
      WALL: 'wall',
      ACID: 'acid'
    };

    const COLORS = {
      empty: '#0a0a0a',
      sand: '#FFB74D',
      water: '#42A5F5',
      wall: '#616161',
      acid: '#66BB6A'
    };

    class FallingSandSimulator {
      constructor(width, height) {
        this.w = width;
        this.h = height;
        this.grid = Array(height).fill(null).map(() => Array(width).fill(CELL_TYPES.EMPTY));
        this.updated = Array(height).fill(null).map(() => Array(width).fill(false));
      }

      get(x, y) {
        if (x < 0 || x >= this.w || y < 0 || y >= this.h) return CELL_TYPES.WALL;
        return this.grid[y][x];
      }

      set(x, y, material) {
        if (x >= 0 && x < this.w && y >= 0 && y < this.h) {
          this.grid[y][x] = material;
        }
      }

      clear() {
        this.grid = Array(this.h).fill(null).map(() => Array(this.w).fill(CELL_TYPES.EMPTY));
        this.updated = Array(this.h).fill(null).map(() => Array(this.w).fill(false));
      }

      tick(n = 1) {
        for (let step = 0; step < n; step++) {
          this.step();
        }
      }

      step() {
        this.updated = Array(this.h).fill(null).map(() => Array(this.w).fill(false));

        for (let y = this.h - 1; y >= 0; y--) {
          for (let x = 0; x < this.w; x++) {
            if (this.updated[y][x]) continue;

            const cell = this.grid[y][x];

            if (cell === CELL_TYPES.SAND) {
              this.processSand(x, y);
            } else if (cell === CELL_TYPES.WATER) {
              this.processWater(x, y);
            } else if (cell === CELL_TYPES.ACID) {
              this.processAcid(x, y);
            }
          }
        }
      }

      processSand(x, y) {
        const below = this.get(x, y + 1);

        if (below === CELL_TYPES.EMPTY) {
          this.grid[y + 1][x] = CELL_TYPES.SAND;
          this.grid[y][x] = CELL_TYPES.EMPTY;
          this.updated[y + 1][x] = true;
          this.updated[y][x] = true;
          return;
        }

        if (below === CELL_TYPES.WATER || below === CELL_TYPES.ACID) {
          this.grid[y + 1][x] = CELL_TYPES.SAND;
          this.grid[y][x] = below;
          this.updated[y + 1][x] = true;
          this.updated[y][x] = true;
          return;
        }

        const directions = Math.random() < 0.5 
          ? [[-1, 1], [1, 1]] 
          : [[1, 1], [-1, 1]];

        for (const [dx, dy] of directions) {
          const nx = x + dx;
          const ny = y + dy;

          if (nx >= 0 && nx < this.w && ny >= 0 && ny < this.h) {
            const cell = this.grid[ny][nx];
            if (cell === CELL_TYPES.EMPTY) {
              this.grid[ny][nx] = CELL_TYPES.SAND;
              this.grid[y][x] = CELL_TYPES.EMPTY;
              this.updated[ny][nx] = true;
              this.updated[y][x] = true;
              return;
            }
          }
        }
      }

      processWater(x, y) {
        const below = this.get(x, y + 1);

        if (below === CELL_TYPES.EMPTY) {
          this.grid[y + 1][x] = CELL_TYPES.WATER;
          this.grid[y][x] = CELL_TYPES.EMPTY;
          this.updated[y + 1][x] = true;
          this.updated[y][x] = true;
          return;
        }

        if (below === CELL_TYPES.SAND || below === CELL_TYPES.ACID) {
          this.grid[y + 1][x] = CELL_TYPES.WATER;
          this.grid[y][x] = below;
          this.updated[y + 1][x] = true;
          this.updated[y][x] = true;
          return;
        }

        const directions = Math.random() < 0.5 
          ? [[-1, 0], [1, 0]] 
          : [[1, 0], [-1, 0]];

        for (const [dx, dy] of directions) {
          const nx = x + dx;
          const ny = y + dy;

          if (nx >= 0 && nx < this.w && ny >= 0 && ny < this.h) {
            const cell = this.grid[ny][nx];
            if (cell === CELL_TYPES.EMPTY) {
              this.grid[ny][nx] = CELL_TYPES.WATER;
              this.grid[y][x] = CELL_TYPES.EMPTY;
              this.updated[ny][nx] = true;
              this.updated[y][x] = true;
              return;
            }
          }
        }
      }

      processAcid(x, y) {
        const below = this.get(x, y + 1);

        if (below === CELL_TYPES.EMPTY) {
          this.grid[y + 1][x] = CELL_TYPES.ACID;
          this.grid[y][x] = CELL_TYPES.EMPTY;
          this.updated[y + 1][x] = true;
          this.updated[y][x] = true;
          return;
        }

        if (below === CELL_TYPES.SAND || below === CELL_TYPES.WATER || below === CELL_TYPES.WALL) {
          this.grid[y + 1][x] = CELL_TYPES.ACID;
          this.grid[y][x] = CELL_TYPES.EMPTY;
          this.updated[y + 1][x] = true;
          this.updated[y][x] = true;
          return;
        }

        const directions = Math.random() < 0.5 
          ? [[-1, 0], [1, 0]] 
          : [[1, 0], [-1, 0]];

        for (const [dx, dy] of directions) {
          const nx = x + dx;
          const ny = y + dy;

          if (nx >= 0 && nx < this.w && ny >= 0 && ny < this.h) {
            const cell = this.grid[ny][nx];
            if (cell === CELL_TYPES.EMPTY || cell === CELL_TYPES.SAND || cell === CELL_TYPES.WATER || cell === CELL_TYPES.WALL) {
              this.grid[ny][nx] = CELL_TYPES.ACID;
              this.grid[y][x] = CELL_TYPES.EMPTY;
              this.updated[ny][nx] = true;
              this.updated[y][x] = true;
              return;
            }
          }
        }
      }
    }

    const canvas = document.getElementById('sand');
    const ctx = canvas.getContext('2d');

    const GRID_WIDTH = 80;
    const GRID_HEIGHT = 80;
    const CELL_PIXELS = canvas.width / GRID_WIDTH;

    const sim = new FallingSandSimulator(GRID_WIDTH, GRID_HEIGHT);

    window.sim = {
      w: GRID_WIDTH,
      h: GRID_HEIGHT,
      get: (x, y) => sim.get(x, y),
      set: (x, y, material) => sim.set(x, y, material),
      clear: () => sim.clear(),
      tick: (n) => sim.tick(n)
    };

    let selectedMaterial = CELL_TYPES.SAND;
    let isDrawing = false;

    document.querySelectorAll('.mat-btn').forEach(btn => {
      btn.addEventListener('click', () => {
        document.querySelectorAll('.mat-btn').forEach(b => b.classList.remove('active'));
        btn.classList.add('active');

        const matMap = {
          'mat-sand': CELL_TYPES.SAND,
          'mat-water': CELL_TYPES.WATER,
          'mat-wall': CELL_TYPES.WALL,
          'mat-acid': CELL_TYPES.ACID,
          'mat-empty': CELL_TYPES.EMPTY
        };
        selectedMaterial = matMap[btn.id];
      });
    });

    document.getElementById('clear').addEventListener('click', () => {
      sim.clear();
    });

    canvas.addEventListener('mousedown', () => { isDrawing = true; });
    canvas.addEventListener('mouseup', () => { isDrawing = false; });
    canvas.addEventListener('mouseleave', () => { isDrawing = false; });

    canvas.addEventListener('mousemove', (e) => {
      if (!isDrawing) return;

      const rect = canvas.getBoundingClientRect();
      const x = e.clientX - rect.left;
      const y = e.clientY - rect.top;

      const gridX = Math.floor(x / CELL_PIXELS);
      const gridY = Math.floor(y / CELL_PIXELS);

      for (let dy = -1; dy <= 1; dy++) {
        for (let dx = -1; dx <= 1; dx++) {
          sim.set(gridX + dx, gridY + dy, selectedMaterial);
        }
      }
    });

    function render() {
      sim.tick(1);

      ctx.fillStyle = COLORS.empty;
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      for (let y = 0; y < GRID_HEIGHT; y++) {
        for (let x = 0; x < GRID_WIDTH; x++) {
          const cell = sim.get(x, y);
          if (cell !== CELL_TYPES.EMPTY) {
            ctx.fillStyle = COLORS[cell];
            ctx.fillRect(x * CELL_PIXELS, y * CELL_PIXELS, CELL_PIXELS, CELL_PIXELS);
          }
        }
      }

      requestAnimationFrame(render);
    }

    render();
  </script>
</body>
</html>
